export const DEFAULT_WATCHLIST = ["AAPL", "MSFT", "GOOGL", "TSLA", "NVDA"];

export const COLORS = [
  "#00f5a0", "#00d9f5", "#f5a200", "#f500d9", "#7b61ff",
  "#ff6161", "#61ffa0", "#ffd061", "#61d4ff", "#ff61b0"
];

export const REFRESH_INTERVAL_MS = 60000; // 60 seconds

export const TABS = ["overview", "chart", "fundamentals", "info"];

export const SORT_OPTIONS = [
  ["symbol", "SYMBOL"],
  ["price", "PRICE"],
  ["changePercent", "CHANGE%"],
];
